DROP DATABASE IF EXISTS artpulse_db;
CREATE DATABASE artpulse_db;
USE artpulse_db;

-- 1. Tabel Utilizatori
CREATE TABLE IF NOT EXISTS users (
    id BIGINT AUTO_INCREMENT PRIMARY KEY,
    email VARCHAR(100) NOT NULL UNIQUE,
    password VARCHAR(255) NOT NULL,
    full_name VARCHAR(100),
    role ENUM('GUEST', 'BIDDER', 'SELLER', 'EXPERT', 'ADMIN') NOT NULL,
    physical_address TEXT,
    status ENUM('ACTIVE', 'DEACTIVATED') DEFAULT 'ACTIVE',
    is_card_validated BOOLEAN DEFAULT FALSE,
    created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP
);

-- 2. Tabel Categorii
CREATE TABLE IF NOT EXISTS categories (
    id BIGINT AUTO_INCREMENT PRIMARY KEY,
    name VARCHAR(50) NOT NULL UNIQUE,
    created_by_expert_id BIGINT,
    FOREIGN KEY (created_by_expert_id) REFERENCES users(id)
);

-- 3. Tabel Produse (Status extins pentru procesul de evaluare)
CREATE TABLE IF NOT EXISTS products (
    id BIGINT AUTO_INCREMENT PRIMARY KEY,
    title VARCHAR(100) NOT NULL,
    description TEXT,
    category_id BIGINT,
    seller_id BIGINT NOT NULL,
    suggested_price DECIMAL(10, 2),
    expert_id BIGINT,
    FOREIGN KEY (expert_id) REFERENCES users(id),
    status ENUM('UNKNOWN', 'PENDING', 'UNDER_REVIEW', 'APPROVED', 'REJECTED') DEFAULT 'UNKNOWN',
    rejection_reason TEXT,
    created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
    FOREIGN KEY (category_id) REFERENCES categories(id),
    FOREIGN KEY (seller_id) REFERENCES users(id)
);

-- 4. Tabel Întâlniri (Pentru evaluarea fizică)
CREATE TABLE IF NOT EXISTS appointments (
    id BIGINT AUTO_INCREMENT PRIMARY KEY,
    product_id BIGINT NOT NULL,
    expert_id BIGINT NOT NULL,
    seller_id BIGINT NOT NULL,
    appointment_date DATETIME NOT NULL,
    location VARCHAR(255) DEFAULT 'Sediul AuraBid',
    status ENUM('SCHEDULED', 'COMPLETED', 'CANCELLED') DEFAULT 'SCHEDULED',
    notes TEXT,
    FOREIGN KEY (product_id) REFERENCES products(id),
    FOREIGN KEY (expert_id) REFERENCES users(id),
    FOREIGN KEY (seller_id) REFERENCES users(id)
);

-- 5. Tabel Licitații
CREATE TABLE IF NOT EXISTS auctions (
    id BIGINT AUTO_INCREMENT PRIMARY KEY,
    product_id BIGINT UNIQUE,
    start_price DECIMAL(10, 2) NOT NULL,
    current_price DECIMAL(10, 2),
    start_time DATETIME NOT NULL,
    end_time DATETIME NOT NULL,
    status ENUM('UPCOMING', 'ACTIVE', 'CLOSED') DEFAULT 'UPCOMING',
    FOREIGN KEY (product_id) REFERENCES products(id)
);

-- 6. Tabel Oferte
CREATE TABLE IF NOT EXISTS bids (
    id BIGINT AUTO_INCREMENT PRIMARY KEY,
    auction_id BIGINT NOT NULL,
    bidder_id BIGINT NOT NULL,
    amount DECIMAL(10, 2) NOT NULL,
    bid_time TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
    FOREIGN KEY (auction_id) REFERENCES auctions(id),
    FOREIGN KEY (bidder_id) REFERENCES users(id)
);

-- 7. Tabel Mesaje
CREATE TABLE IF NOT EXISTS messages (
    id BIGINT AUTO_INCREMENT PRIMARY KEY,
    sender_id BIGINT NOT NULL,
    receiver_id BIGINT NULL,
    product_context_id BIGINT NULL,
    content TEXT,
    attachment_url VARCHAR(255),
    is_appointment_proposal BOOLEAN DEFAULT FALSE,
    sent_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
    FOREIGN KEY (sender_id) REFERENCES users(id),
    FOREIGN KEY (receiver_id) REFERENCES users(id),
    FOREIGN KEY (product_context_id) REFERENCES products(id)
); 

-- 8. Tabel Favorite
CREATE TABLE IF NOT EXISTS favorites (
    user_id BIGINT NOT NULL,
    product_id BIGINT NOT NULL,
    PRIMARY KEY (user_id, product_id),
    FOREIGN KEY (user_id) REFERENCES users(id),
    FOREIGN KEY (product_id) REFERENCES products(id)
); 

-- 9. Tabel Notificări
CREATE TABLE IF NOT EXISTS notifications (
    id BIGINT AUTO_INCREMENT PRIMARY KEY,
    user_id BIGINT NOT NULL,
    auction_id BIGINT,
    message TEXT,
    type ENUM('START', '1_DAY', '1_HOUR', '10_MIN', '5_MIN', '1_MIN', 'INFO') NOT NULL,
    is_read BOOLEAN DEFAULT FALSE,
    sent_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
    FOREIGN KEY (user_id) REFERENCES users(id),
    FOREIGN KEY (auction_id) REFERENCES auctions(id)
); 

-- TABEL NOU: Imagini Produse (Mutat de la Products)
CREATE TABLE IF NOT EXISTS product_images (
    product_id BIGINT NOT NULL,
    image_url LONGTEXT NOT NULL,
    FOREIGN KEY (product_id) REFERENCES products(id)
);

