-- Tabel nou pentru tranzactiile finale
CREATE TABLE IF NOT EXISTS auction_winners (
    id BIGINT AUTO_INCREMENT PRIMARY KEY,
    auction_id BIGINT UNIQUE,
    winner_id BIGINT,
    final_amount DECIMAL(10, 2),
    payment_status ENUM('PENDING', 'PAID', 'FAILED') DEFAULT 'PENDING',
    shipping_status ENUM('NOT_SHIPPED', 'SHIPPED', 'DELIVERED') DEFAULT 'NOT_SHIPPED',
    won_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
    FOREIGN KEY (auction_id) REFERENCES auctions(id),
    FOREIGN KEY (winner_id) REFERENCES users(id)
);

-- VIEW 1: Marketplace (pentru Carduri in React)
CREATE OR REPLACE VIEW view_marketplace AS
SELECT 
    p.id AS product_id, p.title, p.description,
    a.current_price, a.end_time,
    u_seller.full_name AS seller_name,
    u_expert.full_name AS expert_name,
    c.name AS category_name
FROM products p
JOIN auctions a ON p.id = a.product_id
JOIN users u_seller ON p.seller_id = u_seller.id
LEFT JOIN users u_expert ON p.expert_id = u_expert.id
LEFT JOIN categories c ON p.category_id = c.id
WHERE p.status = 'APPROVED' AND a.status = 'ACTIVE';

-- VIEW 2: Statistici Respinse (pentru Admin)
CREATE OR REPLACE VIEW view_admin_rejections AS
SELECT p.id, p.title, u.full_name AS seller_name, p.rejection_reason, p.created_at
FROM products p
JOIN users u ON p.seller_id = u.id
WHERE p.status = 'REJECTED';

-- TRIGGER 1: Actualizare automata pret licitatie
DROP TRIGGER IF EXISTS trg_after_bid_insert;
DELIMITER //
CREATE TRIGGER trg_after_bid_insert
AFTER INSERT ON bids
FOR EACH ROW
BEGIN
    UPDATE auctions 
    SET current_price = NEW.amount 
    WHERE id = NEW.auction_id;
END; //
DELIMITER ;

-- PROCEDURE: Finalizare Licitatie
DROP PROCEDURE IF EXISTS sp_finalize_auction;
DELIMITER //
CREATE PROCEDURE sp_finalize_auction(IN p_auction_id BIGINT)
BEGIN
    DECLARE v_winner_id BIGINT;
    DECLARE v_final_price DECIMAL(10,2);
    
    SELECT bidder_id, amount INTO v_winner_id, v_final_price
    FROM bids WHERE auction_id = p_auction_id
    ORDER BY amount DESC LIMIT 1;
    
    IF v_winner_id IS NOT NULL THEN
        INSERT INTO auction_winners (auction_id, winner_id, final_amount)
        VALUES (p_auction_id, v_winner_id, v_final_price);
    END IF;
    
    UPDATE auctions SET status = 'CLOSED' WHERE id = p_auction_id;
END; //
DELIMITER ;


