-- TRIGGER pt adaugare produs la licitatie
DROP TRIGGER IF EXISTS trg_before_auction_insert;
DELIMITER //
CREATE TRIGGER trg_before_auction_insert
BEFORE INSERT ON auctions
FOR EACH ROW
BEGIN
    DECLARE prod_status VARCHAR(20);

    SELECT status INTO prod_status 
    FROM products 
    WHERE id = NEW.product_id;

    IF prod_status <> 'APPROVED' THEN
        SIGNAL SQLSTATE '45000'
        SET MESSAGE_TEXT = 'Eroare: Produsul trebuie să fie APPROVED pentru a putea începe o licitație!';
    END IF;
END; //
DELIMITER ;

